try {
    // 1. Parse the master item's JSON (the entity list)
    var entities = JSON.parse(value);

    // If the response does not contain an 'entities' array, wrap it.
    // This ensures the script works whether the JSON root is an object or an array.
    if (!entities.hasOwnProperty('entities') && Array.isArray(entities)) {
        entities = { 'entities': entities };
    }

    // 2. Prepare the final output array for LLD
    var results = [];
    var baseUrl = "https://openwifi-prov.andrena.io/api/v1";
    var authToken = "{$TOKEN}";

    // 3. Iterate through each entity in the 'entities' array.
    for (var e = 0; e < entities.entities.length; e++) {
        var entity = entities.entities[e];
        var entityId = entity.id;
        var entityName = entity.name;
        var venueIds = entity.venues || [];

        // 4. For each venue ID, make an HTTP request to get its details.
        for (var v = 0; v < venueIds.length; v++) {
            var venueId = venueIds[v];
            var venueName = "";
            var venueApiUrl = baseUrl + "/venue/" + venueId;

            // Create an HttpRequest object for the API call.
            var request = new HttpRequest();
            request.addHeader("Authorization: Bearer " + authToken);
            request.addHeader("Accept: application/json");

            try {
                var response = request.get(venueApiUrl);
                if (request.getStatus() == 200) {
                    try {
                        var venueData = JSON.parse(response);
                        // The 'name' field is expected in the venue details.
                        venueName = venueData.name ? venueData.name : "";
                    } catch(parseError) {
                        // Handle parsing errors if the response is not valid JSON.
                        Zabbix.log(3, "[Venue Discovery] Failed to parse JSON for venue " + venueId + ": " + parseError);
                    }
                } else {
                    // Log non-200 responses for debugging.
                    Zabbix.log(3, "[Venue Discovery] Failed to get venue " + venueId + ". Status: " + request.getStatus());
                }
            } catch(networkError) {
                // Log network or request errors.
                Zabbix.log(3, "[Venue Discovery] Network error for venue " + venueId + ": " + networkError);
            } finally {
                // If the SDK provides a cleanup method, use it here. Otherwise, just let it be.
                request = null;
            }

            // Add the enriched data to the final results.
            results.push({
                "{#ENTITY_ID}": entityId,
                "{#ENTITY_NAME}": entityName,
                "{#VENUE_ID}": venueId,
                "{#VENUE_NAME}": venueName
            });
        }
    }

    // 5. Return the result as a JSON string for Zabbix LLD to process.
    return JSON.stringify(results);
} catch (error) {
    // Catch any top-level errors and log them.
    Zabbix.log(3, "[Venue Discovery] Fatal error: " + error);
    return "[]";
}

