// ----- Configuration -----
var maxParents = 5;                     // number of parent levels to report
var rootParentUUID = "0000-0000-0000";  // sentinel for root
var entityLimit = 2000;                 // fetch up to 2000 entities

// ----- Helper: fetch all entities (with pagination) -----
function fetchAllEntities(apiKey) {
    var allEntities = [];
    var offset = 0;
    var pageSize = 500;
    var baseUrl = "https://openwifi-prov.andrena.io/api/v1/entity";

    while (true) {
        var url = baseUrl + "?limit=" + pageSize + "&offset=" + offset;
        var req = new HttpRequest();
        req.addHeader("X-API-Key: " + apiKey);
        req.addHeader("Accept: application/json");
        var resp = req.get(url);
        if (req.getStatus() != 200) {
            Zabbix.log(3, "[Venue Discovery] Failed to fetch entities: " + req.getStatus());
            return null;
        }
        var data = JSON.parse(resp);
        var entities = data.entities || [];
        allEntities = allEntities.concat(entities);
        if (entities.length < pageSize) break;
        offset += pageSize;
    }
    return allEntities;
}

