try {
    // 1. Parse the input (array of venues)
    var venues = JSON.parse(value);
    if (!Array.isArray(venues)) {
        throw "Expected array of venues, got " + typeof venues;
    }

    // 2. Get the authentication token from the macro (passed via user macro {$TOKEN})
    //    Note: In Zabbix preprocessing, we can read the macro as a global variable?
    //    Workaround: the script runs in the context of the host, macros are not directly accessible.
    //    Therefore we must embed the token as a string. Better to store it in a global variable or pass via item key parameter.
    //    For simplicity, we assume the token is hardcoded here – you must replace it with your actual token.
    var token = "{$TOKEN}";  // This will NOT be expanded inside JavaScript. Zabbix does not expand macros in preprocessing scripts.
    //    To work around, define a user macro on the host and reference it in the URL? Not possible.
    //    Instead, create a separate master item that stores the token as text and use dependent item? Too complex.
    //    Practical solution: hardcode the token in the script (less secure) or fetch it from a Zabbix API call – not recommended.
    //    Better: Use the same token that the master item uses. Since the master item already sends the token in its headers,
    //    we can extract it from the master item's configuration? Not possible.
    //    Therefore, you MUST hardcode the token in the script below, replacing `YOUR_TOKEN_HERE` with the actual bearer token.
    var apiKey = "62531dd61031ac9a79ab67fdd37750f22ce855fa63d47b4b3bc009bccdc263a9"; // <<< REPLACE WITH YOUR TOKEN

    // 3. Fetch all entities (once)
    var entityList = fetchAllEntities(apiKey);
    if (!entityList) {
        return "[]";
    }

    // 4. Build lookup tables: entity id -> {name, parent}
    var entityMap = {};
    for (var i = 0; i < entityList.length; i++) {
        var e = entityList[i];
        entityMap[e.id] = {
            name: e.name,
            parent: e.parent
        };
    }

    // 5. Prepare result array for LLD
    var lldResults = [];

    // 6. Process each venue
    for (var v = 0; v < venues.length; v++) {
        var venue = venues[v];
        var venueId = venue.id;
        var venueName = venue.name;
        var entityId = venue.entity;

        if (!entityId || !entityMap[entityId]) {
            Zabbix.log(3, "[Venue Discovery] Skipping venue " + venueId + " – missing entity mapping");
            continue;
        }

        // Entity details
        var entityName = entityMap[entityId].name;

        // Build parent chain (up to maxParents)
        var parentIds = [];
        var parentNames = [];
        var currentId = entityMap[entityId].parent;
        var depth = 0;
        while (currentId && currentId !== "" && currentId !== rootParentUUID && depth < maxParents) {
            var parentObj = entityMap[currentId];
            if (!parentObj) break;
            parentIds.push(currentId);
            parentNames.push(parentObj.name);
            currentId = parentObj.parent;
            depth++;
        }
        // Fill empty slots for missing levels
        while (parentIds.length < maxParents) {
            parentIds.push("");
            parentNames.push("");
        }

        // Build macro object
        var lldEntry = {
            "{#VENUE_ID}": venueId,
            "{#VENUE_NAME}": venueName,
            "{#ENTITY_ID}": entityId,
            "{#ENTITY_NAME}": entityName
        };
        for (var i = 1; i <= maxParents; i++) {
            lldEntry["{#PARENT" + i + "_ID}"] = parentIds[i-1];
            lldEntry["{#PARENT" + i + "_NAME}"] = parentNames[i-1];
        }
        lldResults.push(lldEntry);
    }

    return JSON.stringify(lldResults);
} catch (e) {
    Zabbix.log(3, "[Venue Discovery] Fatal error: " + e);
    return "[]";
}
